namespace sv_82717e1534db45d289b8e5abaa5bd0a9.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped per-circuit, so each user gets independent warehouse state.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    public string SelectedWarehouseId { get; private set; } = AvailableWarehouses[0].Id;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == SelectedWarehouseId).Name;

    public int? LowStockCount { get; private set; }

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        LowStockCount = null; // reset until next poll
        OnChange?.Invoke();
    }

    public void UpdateLowStockCount(int count)
    {
        LowStockCount = count;
        OnChange?.Invoke();
    }
}

namespace sv_82717e1534db45d289b8e5abaa5bd0a9.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Simulates a database query for items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB latency
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

