    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_82717e1534db45d289b8e5abaa5bd0a9.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<h4 class="text-muted mb-4">@WarehouseState.SelectedWarehouseName</h4>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card @(alertCardClass)">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                @if (WarehouseState.LowStockCount.HasValue)
                {
                    <p class="display-4 fw-bold mb-1">@WarehouseState.LowStockCount</p>
                    <p class="card-text text-muted">items below minimum level</p>
                }
                else
                {
                    <p class="card-text">
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        Loading&hellip;
                    </p>
                }
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Site</h5>
                <p class="display-6 fw-bold mb-1">@WarehouseState.SelectedWarehouseId</p>
                <p class="card-text text-muted">@WarehouseState.SelectedWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6 mb-1">
                    <span class="badge bg-success">Active</span>
                </p>
                <p class="card-text text-muted">refreshing every 10 s</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;

    private string alertCardClass => WarehouseState.LowStockCount switch
    {
        > 10 => "border-danger",
        > 5  => "border-warning",
        _    => ""
    };

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnStateChanged()
    {
        // Warehouse changed — restart polling for the new warehouse
        await RestartPollingAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Initial fetch
        await PollOnceAsync(token);

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await PollOnceAsync(token);
                }
                catch (OperationCanceledException)
                {
                    break;
                }
            }
        }, token);
    }

    private async Task PollOnceAsync(CancellationToken token)
    {
        if (token.IsCancellationRequested) return;

        var count = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);

        if (token.IsCancellationRequested) return;

        WarehouseState.UpdateLowStockCount(count);
        await InvokeAsync(StateHasChanged);
    }

    private async Task RestartPollingAsync()
    {
        await StopPollingAsync();
        await StartPollingAsync();
    }

    private Task StopPollingAsync()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

